// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	// Add your code here
	if (current.isNewRecord()) {
		if(current.parent){
			current.tasker_process_definition = current.parent.tasker_process_definition;
			current.assigned_to_group = current.parent.assigned_to_group;
			current.assigned_to_individual = current.parent.assigned_to_individual;
			//current.assigned_to_type = current.parent.assigned_to_type;
			current.category = current.parent.category;
			current.classification = current.parent.classification;
			current.demo_data = current.parent.demo_data;
			current.duration = current.parent.duration;

			// STRY0110317 
			current.u_duration_days = current.parent.u_duration_days;
			current.u_duration_time_due = current.parent.u_duration_time_due;

			// STRY0076904
			current.u_wait_for_subtasks_to_finish = current.parent.u_wait_for_subtasks_to_finish;

			current.instructions = current.parent.instructions;
			// RAJ 2018-02-20 - STRY0010804 - When Tasker Definition is created with a parent Tasker Definition, Copy Tasking Authority from Parent.
			current.tasking_authority = current.parent.tasking_authority;
			current.primary_assignee = current.parent.primary_assignee;
			current.primary_office = current.parent.primary_office;
			current.response = current.parent.response;
			current.route_order = 1;
			current.short_description = current.parent.short_description;
			current.sub_category = current.parent.sub_category;

			current.tasker_process_definition = current.parent.tasker_process_definition;
			current.warning_hours = current.parent.warning_hours;
			// RAJ - STRY0010060 - 2018-03-13 Set the default Tasker_Type 
			current.tasker_type = current.parent.tasker_type;

			// STRY0065506 - added  fields added to the Template Task for parity
			current.u_priority = current.parent.u_priority;
			current.u_urgency = current.parent.u_urgency;
			current.u_reviewer = current.parent.u_reviewer;
			current.u_risk_flag = current.parent.u_risk_flag;
			current.u_risk_impact_description = current.parent.u_risk_impact_description;
			current.u_risk_impact_factor = current.parent.u_risk_impact_factor;
			current.u_risk_mitigation_strategy = current.parent.u_risk_mitigation_strategy;
			current.u_risk_probability = current.parent.u_risk_probability;
			current.u_risk_probability_description = current.parent.u_risk_probability_description;
			current.u_risk_reason = current.parent.u_risk_reason;

			// STRY0085130
			current.tasker_type = current.parent.tasker_type;
			current.u_signature_instructions = current.parent.u_signature_instructions;
			current.u_reviewer = current.parent.u_reviewer;
			current.provide_response = current.parent.provide_response;
			current.u_on_behalf_of = current.parent.u_on_behalf_of;

			// STRY0084599 - Need a way for deliver and customers to better synchronize field updates and changes
			current = new CustomTaskerFieldHelper().mapFieldDataOnAction('templateTaskOnDisplayNewChildTemplateTask', current.parent, current);

			// NOTE: we may want to only copy files from parent tasks if they are flagged somehow.
			// also we may want to copy the response documents from parent (marked only)  Or, the attachments object might be just fine.
			//GlideSysAttachment.copy('x_153465_discovert_route_tasks', current.getValue("parent"), 'x_153465_discovert_route_tasks', current.sys_id);

		}
		// RAJ - STRY 0011909 - modify process template
// NOTE: TODO - THIS COMES OUT WHEN WE MOVE TO TOP TASKER DEF
// 		// updated process, this shouldn't happen any more.
//  		else if(!current.tasker_process_definition.nil()){
// 			current.assigned_to_individual = current.sys_created_by;
// 			current.assigned_to_type = 'user';
// 			current.category = current.tasker_process_definition.category;
// 			current.classification = current.tasker_process_definition.classification;
// 			current.demo_data = current.tasker_process_definition.demo_data;
// 			current.duration = current.tasker_process_definition.expected_duration;
// 			current.instructions = current.tasker_process_definition.description;
// 			// RAJ 2018-02-20 - STRY0010804 - When a top level Tasker Definition is created with a parent of Tasker Process Definition, Copy Tasking Authority from the Tasker Process Definition.
// 			current.tasking_authority = current.tasker_process_definition.tasking_authority;

// 			current.primary_assignee = current.tasker_process_definition.primary_assignee;
// 			current.primary_office = current.tasker_process_definition.primary_office;
// 			current.response = current.tasker_process_definition.response;
// 			current.route_order = 1;
// 			current.short_description = current.tasker_process_definition.short_description;
// 			current.sub_category = current.tasker_process_definition.sub_category;
// 			//current.tasker_process_definition = current.tasker_process_definition;
// 			current.warning_hours = current.tasker_process_definition.warning_hours;
// 		}
	}

})(current, previous);
